<div>
  <div id="marketplace-profile-toast" class="hidden fixed right-5 top-5 z-[100000] rounded-md border bg-white px-4 py-3 text-sm shadow"></div>
  <div class="mt-10 flex flex-wrap items-center gap-3">
    <a href="/admin/marketplace" class="box inline-flex h-10 items-center rounded-lg border px-4 text-sm">Inapoi la marketplace</a>
    <div class="ml-auto flex flex-wrap gap-2">
      <button id="marketplace-profile-test" type="button" class="box inline-flex h-10 items-center rounded-lg border px-4 text-sm text-success">Test conexiune</button>
      <button id="marketplace-profile-toggle" type="button" class="box inline-flex h-10 items-center rounded-lg border px-4 text-sm">Activeaza/Dezactiveaza</button>
      <button id="marketplace-profile-delete" type="button" class="box inline-flex h-10 items-center rounded-lg border px-4 text-sm text-danger">Sterge</button>
    </div>
  </div>
  <section class="mt-6 grid grid-cols-12 gap-5">
    <article class="box col-span-12 rounded-lg border bg-white p-6 xl:col-span-4"><div class="flex items-start gap-4"><div class="flex size-14 items-center justify-center rounded-lg bg-primary/10 text-primary"><i data-lucide="plug" class="size-7"></i></div><div class="min-w-0"><h2 id="marketplace-profile-name" class="truncate text-xl font-semibold">Marketplace</h2><p id="marketplace-profile-platform" class="mt-1 text-sm opacity-70">-</p></div></div><div class="mt-6 grid grid-cols-2 gap-3 text-sm"><div><div class="text-xs opacity-60">Plan</div><div id="marketplace-profile-plan" class="font-medium">-</div></div><div><div class="text-xs opacity-60">Status token</div><div id="marketplace-profile-token-status" class="font-medium">-</div></div><div class="col-span-2"><div class="text-xs opacity-60">Cont</div><div id="marketplace-profile-account" class="font-medium">-</div></div><div class="col-span-2"><div class="text-xs opacity-60">Token</div><div id="marketplace-profile-token" class="break-all font-medium">-</div></div></div></article>
    <article class="box col-span-12 rounded-lg border bg-white p-6 xl:col-span-8"><h3 class="text-base font-medium">Descriere</h3><p id="marketplace-profile-notes" class="mt-3 whitespace-pre-wrap text-sm leading-6 opacity-80">-</p><div class="mt-6 grid grid-cols-1 gap-4 md:grid-cols-2"><div class="rounded-lg border p-4"><div class="text-xs opacity-60">Perioada start</div><div id="marketplace-profile-starts" class="mt-1 font-medium">-</div></div><div class="rounded-lg border p-4"><div class="text-xs opacity-60">Perioada sfarsit</div><div id="marketplace-profile-ends" class="mt-1 font-medium">-</div></div><div class="rounded-lg border p-4"><div class="text-xs opacity-60">Produse / cereri / oferte</div><div id="marketplace-profile-stats" class="mt-1 font-medium">-</div></div><div class="rounded-lg border p-4"><div class="text-xs opacity-60">Ultim test</div><div id="marketplace-profile-last-test" class="mt-1 font-medium">-</div></div><div class="rounded-lg border p-4 md:col-span-2"><div class="text-xs opacity-60">API Base URL</div><div id="marketplace-profile-api-url" class="mt-1 break-all font-medium">-</div></div><div class="rounded-lg border p-4 md:col-span-2"><div class="text-xs opacity-60">Webhook URL</div><div id="marketplace-profile-webhook" class="mt-1 break-all font-medium">-</div></div></div></article>
  </section>
</div>
<script>
(function(){'use strict';const ENDPOINT='/admin/api/marketplace_endpoint.php';const randomId=Number(new URLSearchParams(window.location.search).get('id')||0);const toast=document.getElementById('marketplace-profile-toast');let marketplace=null;async function apiCall(action,payload){const response=await fetch(ENDPOINT,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({type_product:action,...payload})});const raw=await response.text();let result;try{result=JSON.parse(raw)}catch(error){throw new Error('Endpoint-ul nu a returnat JSON valid.')}if(!response.ok||!result.success)throw new Error(result.message||'Eroare necunoscuta');return result.data}function escapeHtml(value){return String(value??'').replace(/[&<>"']/g,character=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[character]))}function text(id,value){const element=document.getElementById(id);if(element)element.innerHTML=escapeHtml(value||'-')}function showToast(message,isError){if(!toast)return;toast.textContent=message;toast.classList.remove('hidden');toast.classList.toggle('text-danger',Boolean(isError));setTimeout(()=>toast.classList.add('hidden'),3000)}function maskToken(token){if(!token)return'-';const value=String(token);return value.length<=12?'************':`${value.slice(0,6)}...${value.slice(-6)}`}function render(){text('marketplace-profile-name',marketplace.name);text('marketplace-profile-platform',marketplace.platform);text('marketplace-profile-plan',marketplace.token_plan);text('marketplace-profile-token-status',marketplace.token_status);text('marketplace-profile-account',marketplace.account_email||marketplace.account_name);text('marketplace-profile-token',maskToken(marketplace.api_token));text('marketplace-profile-notes',marketplace.notes||'Fara descriere.');text('marketplace-profile-starts',marketplace.starts_at);text('marketplace-profile-ends',marketplace.ends_at);text('marketplace-profile-stats',`${marketplace.products_synced||0} produse / ${marketplace.requests_today||0} cereri / ${marketplace.offers_sent||0} oferte`);text('marketplace-profile-last-test',`${marketplace.last_test_status||'-'} ${marketplace.last_test_message?'- '+marketplace.last_test_message:''}`);text('marketplace-profile-api-url',marketplace.api_base_url);text('marketplace-profile-webhook',marketplace.webhook_url);document.getElementById('marketplace-profile-toggle').textContent=marketplace.token_status==='active'?'Dezactiveaza':'Activeaza';if(window.lucide)window.lucide.createIcons()}async function load(){if(!randomId)throw new Error('Lipseste id-ul marketplace.');marketplace=await apiCall('get',{randomn_id:randomId});render()}document.getElementById('marketplace-profile-test')?.addEventListener('click',async()=>{try{const result=await apiCall('testconnection',{randomn_id:randomId});showToast(`Test: ${result.last_test_status} - ${result.last_test_message}`,result.last_test_status!=='success');await load()}catch(error){showToast(error.message,true)}});document.getElementById('marketplace-profile-toggle')?.addEventListener('click',async()=>{try{await apiCall('setstatus',{randomn_id:randomId,token_status:marketplace.token_status==='active'?'disabled':'active'});showToast('Status actualizat.',false);await load()}catch(error){showToast(error.message,true)}});document.getElementById('marketplace-profile-delete')?.addEventListener('click',async()=>{if(!confirm('Confirmi stergerea marketplace-ului?'))return;try{await apiCall('delete',{randomn_id:randomId});window.location.href='/admin/marketplace'}catch(error){showToast(error.message,true)}});load().catch(error=>showToast(error.message,true));})();
</script>
